import type { LogEntry, LogLevel, LogsQuery, LogsResponse } from '@motivation/shared';

export interface ClientLogInput {
    level: LogLevel;
    module: string;
    message: string;
    context?: Record<string, unknown>;
}

const DEFAULT_MAX = 500;

export class ClientLogBuffer {
    private entries: LogEntry[] = [];

    constructor(private readonly max: number = DEFAULT_MAX) {}

    push(input: ClientLogInput): void {
        const entry: LogEntry = {
            timestamp: Temporal.Now.instant().toString(),
            level: input.level,
            module: input.module,
            message: input.message,
            ...(input.context ? { context: input.context } : {}),
        };
        this.entries.push(entry);
        if (this.entries.length > this.max) {
            this.entries.splice(0, this.entries.length - this.max);
        }
    }

    snapshot(): LogEntry[] {
        return [...this.entries];
    }

    clear(): void {
        this.entries = [];
    }

    query(filters: Pick<LogsQuery, 'level' | 'search'>): LogsResponse {
        const today = Temporal.Now.plainDateISO().toString();
        let filtered = [...this.entries];

        if (filters.level && filters.level.length > 0) {
            const allowed = new Set<string>(filters.level);
            filtered = filtered.filter((e) => allowed.has(e.level));
        }
        if (filters.search) {
            const needle = filters.search.toLowerCase();
            filtered = filtered.filter((e) =>
                e.message.toLowerCase().includes(needle) ||
                e.module.toLowerCase().includes(needle),
            );
        }

        // Reverse insertion order — newest first. Ties on the millisecond
        // timestamp preserve a monotonic order (Array.reverse is stable).
        filtered.reverse();
        return { date: today, entries: filtered, total: filtered.length };
    }

    toText(): string {
        return this.entries.map((e) => JSON.stringify(e)).join('\n') + '\n';
    }
}

// ── Singleton + install ─────────────────────────────────────────────────────

let singleton: ClientLogBuffer | null = null;
let installed = false;
let cleanupFns: Array<() => void> = [];

export function getClientLogBuffer(): ClientLogBuffer {
    if (!singleton) singleton = new ClientLogBuffer();
    return singleton;
}

export interface InstallOptions {
    buffer?: ClientLogBuffer;
}

const CONSOLE_METHODS: Array<{ name: 'log' | 'info' | 'warn' | 'error' | 'debug'; level: LogLevel }> = [
    { name: 'log',   level: 'info' },
    { name: 'info',  level: 'info' },
    { name: 'warn',  level: 'warn' },
    { name: 'error', level: 'error' },
    { name: 'debug', level: 'debug' },
];

export function installConsoleCapture(options: InstallOptions = {}): ClientLogBuffer {
    const buffer = options.buffer ?? getClientLogBuffer();
    if (options.buffer) singleton = options.buffer;

    if (installed) return buffer;
    installed = true;

    for (const { name, level } of CONSOLE_METHODS) {
        const original = console[name].bind(console);
        const patched = (...args: unknown[]) => {
            try {
                buffer.push(buildEntryFromArgs(level, 'client', args));
            } catch {
                // Never let the logger crash the app.
            }
            original(...args);
        };
        console[name] = patched as typeof console[typeof name];
        cleanupFns.push(() => { console[name] = original as typeof console[typeof name]; });
    }

    const onError = (event: ErrorEvent) => {
        const err = event.error;
        const message = event.message || (err instanceof Error ? err.message : String(err));
        const context: Record<string, unknown> = {};
        if (event.filename) context.filename = event.filename;
        if (typeof event.lineno === 'number') context.lineno = event.lineno;
        if (typeof event.colno === 'number') context.colno = event.colno;
        if (err instanceof Error && err.stack) context.stack = err.stack;
        buffer.push({ level: 'error', module: 'window', message, context: Object.keys(context).length ? context : undefined });
    };
    const onRejection = (event: Event) => {
        const reason = (event as unknown as { reason?: unknown }).reason;
        const message = reason instanceof Error ? reason.message : safeStringify(reason);
        const context: Record<string, unknown> = {};
        if (reason instanceof Error && reason.stack) context.stack = reason.stack;
        buffer.push({
            level: 'error',
            module: 'window',
            message: `Unhandled promise rejection: ${message}`,
            context: Object.keys(context).length ? context : undefined,
        });
    };

    window.addEventListener('error', onError as EventListener);
    window.addEventListener('unhandledrejection', onRejection as EventListener);
    cleanupFns.push(() => {
        window.removeEventListener('error', onError as EventListener);
        window.removeEventListener('unhandledrejection', onRejection as EventListener);
    });

    return buffer;
}

/** Test-only: undo console patching and reset the singleton. */
export function resetClientLogCaptureForTests(): void {
    for (const fn of cleanupFns) fn();
    cleanupFns = [];
    installed = false;
    singleton = null;
}

function buildEntryFromArgs(level: LogLevel, module: string, args: unknown[]): ClientLogInput {
    if (args.length === 0) return { level, module, message: '' };
    const [first, ...rest] = args;
    const message = typeof first === 'string' ? first : safeStringify(first);
    if (rest.length === 0) return { level, module, message };
    return {
        level,
        module,
        message,
        context: { args: rest.map(safeClone) },
    };
}

function safeStringify(value: unknown): string {
    try {
        return typeof value === 'string' ? value : JSON.stringify(value, circularReplacer());
    } catch {
        return String(value);
    }
}

function safeClone(value: unknown): unknown {
    try {
        return JSON.parse(JSON.stringify(value, circularReplacer()));
    } catch {
        return String(value);
    }
}

function circularReplacer(): (key: string, value: unknown) => unknown {
    const seen = new WeakSet<object>();
    return (_key, value) => {
        if (value instanceof Error) {
            return { name: value.name, message: value.message, stack: value.stack };
        }
        if (typeof value === 'object' && value !== null) {
            if (seen.has(value)) return '[Circular]';
            seen.add(value);
        }
        return value;
    };
}
